const express = require('express');
const app = express();
const fs = require('fs');
const path = require('path');
const { parseString } = require('xml2js');

// Set up middleware to handle multipart/form-data requests
app.use(express.multipart());

// Define a route for uploading XML files
app.post('/upload-xml', (req, res) => {
  const xmlFile = req.files.xmlfile;
  const filePath = path.join(__dirname, 'uploads', xmlFile.name);

  // Save the uploaded file to disk
  fs.readFile(xmlFile.path, (err, data) => {
    if (err) {
      console.error(err);
      res.status(500).send({ message: 'Error reading uploaded file' });
    } else {
      const filePath = path.join(__dirname, 'uploads', xmlFile.name);

      // Parse the XML using xml2js
      parseString(data.toString(), (err, result) => {
        if (err) {
          console.error(err);
          res.status(500).send({ message: 'Error parsing uploaded file' });
        } else {
          const configSettings = {};

          // Extract configuration settings from the parsed XML
          Object.keys(result).forEach((key) => {
            configSettings[key] = result[key][0];
          });

          // Save the extracted configuration settings to a JSON file
          fs.writeFile(path.join(__dirname, 'config.json'), JSON.stringify(configSettings), (err) => {
            if (err) {
              console.error(err);
              res.status(500).send({ message: 'Error saving config settings' });
            } else {
              res.send({ message: 'XML uploaded and processed successfully', configSettings });
            }
          });
        }
      });
    }
  });
});

// Start the server
const port = 3000;
app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});